const p = msg.payload;
if (!context.prev) { context.prev = p.raw; }
let delta = p.raw - context.prev;
if (delta > 2048) delta -= 4096;
if (delta < -2048) delta += 4096;
context.prev = p.raw;
msg.payload = {
    angle: p.angle,
    raw: p.raw,
    velocity: (delta * 10 * 2 * Math.PI / 4096).toFixed(3) + ' rad/s',
    magnet: p.magnet_detected
};
return msg;
